    """Second-pass resolution for options whose ``default`` is a
    dynamic mapping (see :class:`Option`). This runs after every
    parameter has consumed its value from the command line,
    environment variables, and config/default maps, so the current
    values of the referenced source options are final.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or param._dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

